# Skill composition patterns
from typing import Any, Callable
from dataclasses import dataclass
import asyncio, json

@dataclass
class SkillResult:
    success: bool
    data: Any
    error: str | None = None
    duration_ms: float = 0.0


class Skill:
    """Base class for all skills."""
    name: str = ""
    description: str = ""

    async def execute(self, **kwargs) -> SkillResult:
        raise NotImplementedError

    def get_manifest(self) -> dict:
        return {
            "name": self.name,
            "description": self.description,
            "input_schema": self._input_schema(),
            "output_schema": self._output_schema()
        }

    def _input_schema(self) -> dict:
        return {"type": "object", "properties": {}}

    def _output_schema(self) -> dict:
        return {"type": "object", "properties": {}}


# === Pattern 1: Chaining (output -> input) ===
class SkillChain:
    """Execute skills in sequence, passing output to input."""
    def __init__(self, skills: list[Skill]):
        self.skills = skills

    async def execute(self, **initial_input) -> SkillResult:
        current_input = initial_input
        for skill in self.skills:
            result = await skill.execute(**current_input)
            if not result.success:
                return result
            current_input = {"input": result.data}
        return SkillResult(success=True, data=current_input)


# === Pattern 2: Router (dispatch based on input) ===
class SkillRouter:
    """Route to different skills based on input classification."""
    def __init__(self, router_fn: Callable, skills: dict[str, Skill]):
        self.router = router_fn  # input -> skill_name
        self.skills = skills

    async def execute(self, **kwargs) -> SkillResult:
        skill_name = self.router(kwargs)
        skill = self.skills.get(skill_name)
        if not skill:
            return SkillResult(False, None, f"No skill found for: {skill_name}")
        return await skill.execute(**kwargs)


# === Pattern 3: Parallel fan-out ===
class SkillFanOut:
    """Execute multiple skills in parallel, combine results."""
    def __init__(self, skills: list[Skill], combiner: Callable = None):
        self.skills = skills
        self.combiner = combiner or (lambda results: "\n".join(str(r) for r in results))

    async def execute(self, **kwargs) -> SkillResult:
        tasks = [skill.execute(**kwargs) for skill in self.skills]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        processed = []
        for r in results:
            if isinstance(r, Exception):
                processed.append(SkillResult(False, None, str(r)))
            else:
                processed.append(r)
        combined = self.combiner([p.data for p in processed])
        return SkillResult(success=all(p.success for p in processed), data=combined)


# === Pattern 4: Fallback chain ===
class SkillFallbackChain:
    """Try skills in order until one succeeds."""
    def __init__(self, skills: list[Skill]):
        self.skills = skills

    async def execute(self, **kwargs) -> SkillResult:
        errors = []
        for skill in self.skills:
            result = await skill.execute(**kwargs)
            if result.success:
                return result
            errors.append(f"{skill.name}: {result.error}")
        return SkillResult(False, None, "All skills failed: " + "; ".join(errors))


